type Eleve = {
  id: string;
  nom: string;
  prenom: string;
  password?: string;
  // ... other fields
};

const [eleves, setEleves] = useState<Eleve[]>([]);

const loadElevesFromServer = async () => {
  try {
    setLoading(true);
    setLastError('');

    const r = await fetch(REMOTE_JSON_URL, {
      cache: 'no-store',
      headers: { 'X-API-KEY': 'KEYOFSQUAD01@' }
    });

    if (!r.ok) throw new Error(`HTTP ${r.status}`);

    const rawData = await r.json();
    const arr = parseArrayResponse(rawData);

    setData(arr);
    setLastSyncTime(formatTime(new Date()));

    await saveCopyLocally(arr);
  } catch (error: any) {
    setLastError(error?.message || 'Erreur');
    Alert.alert('Erreur', error?.message);
  } finally {
    setLoading(false);
  }
};

